# Unit Tests for `camel_to_snake`

```python
import pytest
from your_module import camel_to_snake  # Replace with actual module name


class TestCamelToSnake:
    """Test suite for camel_to_snake function."""

    # Happy path tests
    def test_simple_camel_case(self):
        """Test conversion of simple camelCase string."""
        assert camel_to_snake("camelCase") == "camel_case"

    def test_multiple_words(self):
        """Test conversion with multiple camelCase words."""
        assert camel_to_snake("myVariableName") == "my_variable_name"

    def test_single_word_lowercase(self):
        """Test that single lowercase word remains unchanged."""
        assert camel_to_snake("hello") == "hello"

    def test_single_word_uppercase(self):
        """Test that single uppercase word is converted to lowercase."""
        assert camel_to_snake("Hello") == "hello"

    def test_already_snake_case(self):
        """Test that snake_case input remains unchanged."""
        assert camel_to_snake("already_snake_case") == "already_snake_case"

    def test_pascal_case(self):
        """Test conversion of PascalCase (UpperCamelCase)."""
        assert camel_to_snake("PascalCase") == "pascal_case"

    def test_consecutive_capitals(self):
        """Test handling of consecutive capital letters."""
        assert camel_to_snake("HTTPResponse") == "h_t_t_p_response"

    def test_numbers_in_string(self):
        """Test that numbers are preserved."""
        assert camel_to_snake("variable2Name") == "variable2_name"

    def test_numbers_at_start(self):
        """Test string starting with numbers."""
        assert camel_to_snake("2FastVariable") == "2_fast_variable"

    # Edge cases
    def test_empty_string(self):
        """Test conversion of empty string."""
        assert camel_to_snake("") == ""

    def test_single_character_lowercase(self):
        """Test single lowercase character."""
        assert camel_to_snake("a") == "a"

    def test_single_character_uppercase(self):
        """Test single uppercase character."""
        assert camel_to_snake("A") == "a"

    def test_two_character_camel_case(self):
        """Test two character camelCase."""
        assert camel_to_snake("aB") == "a_b"

    def test_all_uppercase(self):
        """Test all uppercase string."""
        assert camel_to_snake("ALLUPPERCASE") == "alluppercase"

    def test_all_lowercase(self):
        """Test all lowercase string."""
        assert camel_to_snake("alllowercase") == "alllowercase"

    def test_underscore_already_present(self):
        """Test string with existing underscores."""
        assert camel_to_snake("camel_Case_Name") == "camel__case__name"

    def test_special_characters(self):
        """Test string with special characters."""
        assert camel_to_snake("camel-Case@Name") == "camel-case@name"

    def test_spaces_in_string(self):
        """Test string with spaces."""
        assert camel_to_snake("camel Case Name") == "camel case name"

    def test_leading_uppercase(self):
        """Test string starting with uppercase."""
        assert camel_to_snake("CamelCase") == "camel_case"

    def test_trailing_uppercase(self):
        """Test string ending with uppercase."""
        assert camel_to_snake("camelCASE") == "camel_c_a_s_e"

    def test_mixed_case_with_numbers(self):
        """Test complex mixed case with numbers."""
        assert camel_to_snake("myVar123Name456Test") == "my_var123_name456_test"
